from flask import Flask, request
from prometheus_client import Counter, generate_latest, CollectorRegistry
from prometheus_client.exposition import basic_auth_handler
from prometheus_client import make_wsgi_app
from werkzeug.middleware.dispatcher import DispatcherMiddleware

app = Flask(__name__)
registry = CollectorRegistry()

# Global counter for tracking requests
request_counter = Counter('http_requests_total', 'Total HTTP Requests', ['user_id', 'session_id', 'path'], registry=registry)

@app.route('/metrics')
def metrics():
    return generate_latest(registry)

@app.before_request
def track_requests():
    user_id = request.headers.get('X-User-ID', 'unknown')
    session_id = request.headers.get('X-Session-ID', 'unknown')
    path = request.path

    # Increment the counter for the specific user-path combination
    request_counter.labels(user_id=user_id, session_id=session_id, path=path).inc()

# Middleware for basic auth on metrics endpoint
app.wsgi_app = DispatcherMiddleware(app.wsgi_app, {
    '/metrics': make_wsgi_app(registry, basic_auth_handler('username', 'password'))
})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)